// ─── Утилиты ─────────────────────────────────────────────────────────────────

function safeGetValue(accId, serviceId, charId, context, fallback) {
    if (fallback === undefined) fallback = null;
    try {
        var acc = Hub.getAccessory(accId);
        if (!acc) throw new Error("accessory=null");
        var service = acc.getService(serviceId);
        if (!service) throw new Error("service " + serviceId + "=null");
        var ch = service.getCharacteristic(charId);
        if (!ch) throw new Error("char " + charId + "=null");
        return ch.value;
    } catch (e) {
        log.error("⛔ safeGetValue | " + context + " | acc=" + accId + ", svc=" + serviceId + ", char=" + charId + " → " + e.message);
        return fallback;
    }
}

function sendTG(message) {
    try {
        Notify.text(message).to("Telegram_1", 1).send();
    } catch (e) {
        log.error("⛔ Ошибка отправки Telegram: " + e.message);
    }
}

// ─── Получить сервис по UUID "accId.svcId" ───────────────────────────────────
function getSvcByUUID(uuid) {
    if (!uuid || uuid === "") return null;
    try {
        var parts = uuid.split(".");
        return Hub.getAccessory(parts[0]).getService(parts[1]);
    } catch (e) {
        log.warn("⛔ getSvcByUUID(" + uuid + "): " + e.message);
        return null;
    }
}

// ─── Чтение характеристики по UUID сервиса ───────────────────────────────────
function readCharByUUID(uuid, charType, fallback) {
    if (fallback === undefined) fallback = null;
    if (!uuid || uuid === "") return fallback;
    try {
        var svc = getSvcByUUID(uuid);
        if (!svc) return fallback;
        var ch = svc.getCharacteristic(charType);
        if (!ch) return fallback;
        var v = ch.getValue();
        return (v !== null && v !== undefined && !isNaN(v)) ? v : fallback;
    } catch (e) {
        log.warn("⛔ readCharByUUID(" + uuid + "): " + e.message);
        return fallback;
    }
}

// ─── Инициализация глобальных переменных (onStart) ───────────────────────────
if (!global.lastRoomTemps)      global.lastRoomTemps      = {};
if (!global.lastExternalData)   global.lastExternalData   = { temp: 0, temp_min_6_hours: 0, wind: 0, uv: 0, cloud: 0 };
if (!global.stableColdRoomCount) global.stableColdRoomCount = 0;
if (!global.stableHotRoomCount)  global.stableHotRoomCount  = 0;
if (!global.lastColdestRoom)    global.lastColdestRoom    = "";
if (!global.ignoredRooms)       global.ignoredRooms       = {};
if (!global.ventilationStatus)  global.ventilationStatus  = {};
if (!global.windowStatus)       global.windowStatus       = {};
if (!global.floorHeatingState)  global.floorHeatingState  = {};

var ignoreTemperature = {};

// ─── Старые функции (обратная совместимость без ctx) ─────────────────────────

function isWindowOpen(room) {
    var windowStates = [];
    switch (room) {
        case "Гост-ая":
            windowStates = [safeGetValue(385,13,15,"Окно Гост-ая #1",0), safeGetValue(386,13,15,"Окно Гост-ая #2",0)]; break;
        case "Спальня":
            windowStates = [safeGetValue(370,13,15,"Окно Спальня",0)]; break;
        case "Детская":
            windowStates = [safeGetValue(371,13,15,"Окно Детская #1",0), safeGetValue(389,13,15,"Окно Детская #2",0)]; break;
        case "Кухня 🍽️":
            windowStates = [safeGetValue(388,13,15,"Окно Кухня #1",0), safeGetValue(387,13,15,"Окно Кухня #2",0)]; break;
        default:
            log.error("Комната " + room + " не найдена в списке окон"); return false;
    }
    return windowStates.some(function(v) { return v === 1; });
}

function isVentilationOn(room) {
    var value = 0;
    switch (room) {
        case "Гост-ая": value = safeGetValue(410,13,15,"Вентиляция Гост-ая",0); break;
        case "Спальня":  value = safeGetValue(268,13,15,"Вентиляция Спальня",0); break;
        case "Кухня 🍽️": case "Детская": value = 0; break;
        default: log.error("Комната " + room + " не найдена в вентиляции"); return false;
    }
    return value === 1;
}

function isFloorHeatingOn(room) {
    var raw;
    switch (room) {
        case "Спальня":   raw = safeGetValue(479,22,24,"ТП Спальня",0); break;
        case "Детская":   raw = safeGetValue(479,13,15,"ТП Детская",0); break;
        case "Гост-ая":   raw = safeGetValue(479,16,18,"ТП Гост-ая",0); break;
        case "Кухня 🍽️": raw = safeGetValue(479,19,21,"ТП Кухня",0);   break;
        default: return false;
    }
    var isOn = (raw === 1 || raw === true || raw === "1");
    global.floorHeatingState[room] = isOn;
    return isOn;
}

function isRadiatorOn(room) {
    var states = [];
    switch (room) {
        case "Гост-ая":
            states = [safeGetValue(307,13,15,"Радиатор Гост-ая #1",0), safeGetValue(304,13,15,"Радиатор Гост-ая #2",0)]; break;
        case "Спальня":
            states = [safeGetValue(303,13,15,"Радиатор Спальня",0)]; break;
        case "Детская":
            states = [safeGetValue(308,13,15,"Радиатор Детская #1",0), safeGetValue(309,13,15,"Радиатор Детская #2",0)]; break;
        case "Кухня 🍽️":
            states = [safeGetValue(296,13,15,"Радиатор Кухня",0)]; break;
        default: log.error("Комната " + room + " не найдена в радиаторах"); return false;
    }
    return states.some(function(v) { return v === 1; });
}

function isBoilerOn() {
    var raw = safeGetValue(275,13,15,"Котёл Active",0);
    var isOn = (raw === 1 || raw === true || raw === "1");
    global.boilerState = isOn;
    return isOn;
}

function getAirQualityData(room) {
    switch (room) {
        case "Спальня":   return { value: safeGetValue(249,27,30,"CO2 Спальня",null), unit: "ppm", type: "CO₂" };
        case "Гост-ая":   return { value: safeGetValue(509,27,30,"CO2 Гост-ая",null), unit: "ppm", type: "CO₂" };
        case "Кухня 🍽️": return { value: safeGetValue(483,19,22,"TVOC Кухня",null),  unit: "ppb", type: "TVOC" };
        default: return null;
    }
}

// ─── Новые функции — через cfg комнаты из ctx ─────────────────────────────────

function isWindowOpenCtx(rCfg) {
    var windows = (rCfg.windows || []).filter(function(w) { return w && w !== ""; });
    for (var i = 0; i < windows.length; i++) {
        try {
            var svc = getSvcByUUID(windows[i]);
            if (!svc) continue;
            if (svc.getCharacteristic(HC.ContactSensorState).getValue() === 1) return true;
        } catch(e) {}
    }
    return false;
}

function isVentilationOnCtx(rCfg) {
    if (!rCfg.ventilation || rCfg.ventilation === "") return false;
    try {
        var svc = getSvcByUUID(rCfg.ventilation);
        if (!svc) return false;
        var val = svc.getCharacteristic(HC.Active) || svc.getCharacteristic(HC.On);
        return val ? (val.getValue() === 1 || val.getValue() === true) : false;
    } catch(e) { return false; }
}

function isFloorHeatingOnCtx(rCfg) {
    if (!rCfg.floorHeating || rCfg.floorHeating === "") return false;
    try {
        var svc = getSvcByUUID(rCfg.floorHeating);
        if (!svc) return false;
        var val = svc.getCharacteristic(HC.On);
        return val ? (val.getValue() === 1 || val.getValue() === true) : false;
    } catch(e) { return false; }
}

function isRadiatorOnCtx(rCfg) {
    // radiatorType === "thermostat": CurrentHeatingCoolingState > 0
    var rads = (rCfg.radiators || []).filter(function(r) { return r && r !== ""; });
    for (var i = 0; i < rads.length; i++) {
        try {
            var svc = getSvcByUUID(rads[i]);
            if (!svc) continue;
            var val = svc.getCharacteristic(HC.CurrentHeatingCoolingState);
            if (val && val.getValue() > 0) return true;
        } catch(e) {}
    }
    return false;
}

function isBoilerOnCtx(boilerUUID) {
    if (!boilerUUID || boilerUUID === "") return isBoilerOn();
    try {
        var svc = getSvcByUUID(boilerUUID);
        if (!svc) return false;
        var val = svc.getCharacteristic(HC.CurrentHeatingCoolingState);
        return val ? val.getValue() > 0 : false;
    } catch(e) { return false; }
}

function getAirQualityDataCtx(rCfg) {
    var aq = rCfg.airQuality;
    if (!aq || !aq.service || aq.service === "") return null;
    try {
        var svc = getSvcByUUID(aq.service);
        if (!svc) return null;
        var charType = (aq.char === "voc") ? HC.VOCDensity : HC.CarbonDioxideLevel;
        var val = svc.getCharacteristic(charType);
        if (!val) return null;
        return { value: val.getValue(), type: aq.type, unit: aq.char === "voc" ? "ppb" : "ppm" };
    } catch(e) { return null; }
}

function readTargetTempCtx(rCfg) {
    if (!rCfg.thermostat || rCfg.thermostat === "") return rCfg.targetDefault;
    var v = readCharByUUID(rCfg.thermostat, HC.TargetTemperature, null);
    return (v !== null) ? v : rCfg.targetDefault;
}

function readRoomTempCtx(rCfg) {
    if (!rCfg.tempSensor || rCfg.tempSensor === "") return null;
    return readCharByUUID(rCfg.tempSensor, HC.CurrentTemperature, null);
}

// ─── Чтение погодных данных: датчик → fallback global.yr → fallback кэш ──────
function readWeather(sensorUUID, charType, yrKey, cacheKey, fallback) {
    // 1. Внешний датчик из логического сценария
    if (sensorUUID && sensorUUID !== "") {
        var v = readCharByUUID(sensorUUID, charType, null);
        if (v !== null) return v;
    }
    // 2. global.yr (прогноз погоды)
    if (global.yr && global.yr[yrKey] != null) return global.yr[yrKey];
    // 3. Кэш последних известных данных
    if (global.lastExternalData && global.lastExternalData[cacheKey] != null) return global.lastExternalData[cacheKey];
    return fallback;
}

// ─── Обновление игнорируемых комнат ──────────────────────────────────────────
function updateIgnoredRooms(rooms, roomsCfg) {
    if (!rooms) { log.error("rooms не определено в updateIgnoredRooms"); return; }
    Object.keys(rooms).forEach(function(room) {
        var windowOpen, ventOn;
        if (roomsCfg && roomsCfg[room]) {
            windowOpen = isWindowOpenCtx(roomsCfg[room]);
            ventOn     = isVentilationOnCtx(roomsCfg[room]);
        } else {
            windowOpen = isWindowOpen(room);
            ventOn     = isVentilationOn(room);
        }
        log.info("Комната: " + room + ", Окно: " + windowOpen + ", Вентиляция: " + ventOn);
        ignoreTemperature[room] = (windowOpen || ventOn);
        log.info("Температура в " + room + " " + (ignoreTemperature[room] ? "игнорируется" : "учитывается"));
    });
}

// ─── Поиск самой холодной комнаты ────────────────────────────────────────────
function getColdestRoom(rooms) {
    if (!rooms) { log.error("rooms не определено в getColdestRoom"); return null; }
    var sorted = Object.keys(rooms)
        .filter(function(r) { return !ignoreTemperature[r]; })
        .filter(function(r) { return rooms[r].sensor < rooms[r].target; })
        .sort(function(a,b) { return (rooms[b].target - rooms[b].sensor) - (rooms[a].target - rooms[a].sensor); });
    if (sorted.length === 0) {
        log.info("Все комнаты выше целевой или игнорируются. Используем наибольшее отклонение.");
        sorted = Object.keys(rooms)
            .filter(function(r) { return !ignoreTemperature[r]; })
            .sort(function(a,b) { return (rooms[b].target - rooms[b].sensor) - (rooms[a].target - rooms[a].sensor); });
    }
    return sorted.length ? sorted[0] : null;
}

// ─── Запись температуры теплоносителя ────────────────────────────────────────
function setBoilerTemp(boilerUUID, temp) {
    if (boilerUUID && boilerUUID !== "") {
        // Новый режим: через UUID из логического сценария
        try {
            var svc = getSvcByUUID(boilerUUID);
            if (!svc) throw new Error("service null");
            svc.getCharacteristic(HC.TargetTemperature).setValue(temp);
        } catch(e) {
            log.error("⛔ setBoilerTemp(uuid): " + e.message);
        }
    } else {
        // Старый режим: хардкодированный accId=275
        try {
            var acc = Hub.getAccessory(275);
            if (!acc) throw new Error("accessory=null");
            var svc = acc.getService(13);
            if (!svc) throw new Error("service=13 null");
            var ch = svc.getCharacteristic(18);
            if (!ch) throw new Error("char=18 null");
            ch.setValue(temp);
        } catch(e) {
            log.error("⛔ setBoilerTemp(hardcode): " + e.message);
        }
    }
}

// ═════════════════════════════════════════════════════════════════════════════
// ГЛАВНАЯ ФУНКЦИЯ — принимает ctx из логического сценария v2.1
// Без ctx — полная обратная совместимость со старым поведением
// ═════════════════════════════════════════════════════════════════════════════
global.adjust_heating = function(ctx) {
    try {
        if (typeof Hub === "undefined" || Hub == null) {
            log.error("⛔ Hub недоступен.");
            return;
        }

        // ── Параметры из ctx (логический сценарий v2.1) ──────────────────────
        var roomsCfg      = (ctx && ctx.rooms)            ? ctx.rooms            : null;
        var boilerUUID    = (ctx && ctx.boilerService)    ? ctx.boilerService    : null;
        var baseAt0       = (ctx && ctx.baseWaterTempAt0 != null) ? ctx.baseWaterTempAt0 : 53;
        var waterMin      = (ctx && ctx.waterTempMin != null)     ? ctx.waterTempMin     : 40;
        var waterMax      = (ctx && ctx.waterTempMax != null)     ? ctx.waterTempMax     : 80;
        var doTelegram    = (ctx && ctx.sendTelegram != null)     ? ctx.sendTelegram     : true;
        var weatherSensors = (ctx && ctx.weatherSensors) ? ctx.weatherSensors : {};

        // ── Погодные данные: датчики → global.yr → кэш ───────────────────────
        var outsideTemp  = readWeather(weatherSensors.outdoorTemp, HC.CurrentTemperature,  "temp",            "temp",            0);
        var forecastTemp = readWeather(null,                        null,                   "temp_min_6_hours","temp_min_6_hours", outsideTemp);
        var windSpeed    = readWeather(weatherSensors.wind,        HC.C_Angle,             "wind",            "wind",            0);
        var cloudiness   = readWeather(weatherSensors.cloud,       HC.CarbonDioxideLevel,  "cloud",           "cloud",           0);
        var uvIndex      = readWeather(weatherSensors.uv,          HC.C_Integer,           "uv",              "uv",              0);

        global.lastExternalData = { temp: outsideTemp, temp_min_6_hours: forecastTemp, wind: windSpeed, cloud: cloudiness, uv: uvIndex };

        // ── Базовая температура теплоносителя ────────────────────────────────
        var baseWaterTemp = baseAt0 + (0 - outsideTemp) * 1;
        baseWaterTemp += (forecastTemp - outsideTemp) / 2;

        var windCorrection = 0;
        if      (windSpeed >= 10)              windCorrection = 3;
        else if (windSpeed >= 6)               windCorrection = 2;
        else if (windSpeed >= 3)               windCorrection = 1;
        baseWaterTemp += windCorrection;

        var cloudEmoji = "☀️";
        if      (cloudiness >= 80)             cloudEmoji = "☁️";
        else if (cloudiness >= 50)             cloudEmoji = "⛅";
        else if (cloudiness >= 30)             cloudEmoji = "🌤";

        var uvCorrection = 0;
        if      (uvIndex > 2.5)  { uvCorrection = cloudiness < 30 ? -5 : cloudiness < 50 ? -4 : cloudiness < 80 ? -3 : 0; }
        else if (uvIndex >= 1.5) { uvCorrection = cloudiness < 30 ? -4 : cloudiness < 50 ? -3 : cloudiness < 80 ? -2 : 0; }
        else if (uvIndex >= 0.8) { uvCorrection = cloudiness < 30 ? -3 : cloudiness < 50 ? -2 : cloudiness < 80 ? -1 : 0; }
        baseWaterTemp += uvCorrection;

        // Пороги из ctx (или дефолтные 40/80)
        if (baseWaterTemp < waterMin) baseWaterTemp = waterMin;
        if (baseWaterTemp > waterMax) baseWaterTemp = waterMax;

        // ── Данные комнат ─────────────────────────────────────────────────────
        var rooms = {};
        if (roomsCfg) {
            // Новый режим: из логического сценария
            for (var rName in roomsCfg) {
                var rCfg   = roomsCfg[rName];
                var target = readTargetTempCtx(rCfg);
                var sensor = readRoomTempCtx(rCfg);
                rooms[rName] = { target: target, sensor: sensor, cfg: rCfg };
            }
        } else {
            // Обратная совместимость: хардкодированные accId
            rooms = {
                "Спальня":    { target: safeGetValue(488,13,18,"Целевая Спальня",24), sensor: safeGetValue(428,13,15,"Температура Спальня",null) },
                "Детская":    { target: safeGetValue(487,13,18,"Целевая Детская",24), sensor: safeGetValue(512,13,15,"Температура Детская",null) },
                "Гост-ая":    { target: safeGetValue(480,13,18,"Целевая Гост-ая",24), sensor: safeGetValue(302,13,15,"Температура Гост-ая",null) },
                "Кухня 🍽️": { target: safeGetValue(486,13,18,"Целевая Кухня",24),   sensor: safeGetValue(483,13,15,"Температура Кухня",null)   }
            };
        }

        // Подстановка fallback температуры при недоступном датчике
        for (var room in rooms) {
            if (rooms[room].sensor == null || isNaN(rooms[room].sensor)) {
                log.warn("Датчик " + room + " недоступен. Используем последнее значение.");
                rooms[room].sensor = global.lastRoomTemps[room] || rooms[room].target;
            } else {
                global.lastRoomTemps[room] = rooms[room].sensor;
            }
        }

        for (var room in rooms) {
            log.info("Комната: " + room + ", Цель: " + rooms[room].target + ", Сейчас: " + rooms[room].sensor + ", Δ=" + (rooms[room].target - rooms[room].sensor).toFixed(2));
        }

        // ── Игнорирование комнат и поиск самой холодной ──────────────────────
        updateIgnoredRooms(rooms, roomsCfg);
        var coldestRoom = getColdestRoom(rooms);

        if (!coldestRoom) {
            log.error("Не удалось определить самую холодную комнату.");
            if (doTelegram) sendTG("⚠️ Ошибка: не удалось определить самую холодную комнату.");
            return;
        }

        var minDelta = Math.round((rooms[coldestRoom].target - rooms[coldestRoom].sensor) * 10) / 10;

        // ── Текущая температура теплоносителя ────────────────────────────────
        var currentWaterTemp;
        if (boilerUUID) {
            currentWaterTemp = readCharByUUID(boilerUUID, HC.TargetTemperature, null);
        }
        if (currentWaterTemp == null || isNaN(currentWaterTemp)) {
            currentWaterTemp = safeGetValue(275,13,18,"Текущий теплоноситель", global.lastWaterTemp || 50);
        }
        if (currentWaterTemp == null || isNaN(currentWaterTemp)) currentWaterTemp = global.lastWaterTemp || 50;
        global.lastWaterTemp = currentWaterTemp;

        // ── Стабильность ──────────────────────────────────────────────────────
        if (coldestRoom === global.lastColdestRoom) {
            if (minDelta > 0.2)  global.stableColdRoomCount++;
            else                 global.stableColdRoomCount = 0;
            if (minDelta <= -0.2) global.stableHotRoomCount++;
            else                  global.stableHotRoomCount = 0;
        } else {
            global.stableColdRoomCount = 0;
            global.stableHotRoomCount  = 0;
        }
        if (minDelta > 0.2)   global.stableColdRoomCount++;
        else                  global.stableColdRoomCount = 0;
        if (minDelta <= -0.2) global.stableHotRoomCount++;
        else                  global.stableHotRoomCount  = 0;

        // ── Многоступенчатая коррекция Δ ─────────────────────────────────────
        if      (global.stableColdRoomCount >= 5) { minDelta += 2;   log.info("🔼 Стабильно холодно 5 циклов. Δ +2°C"); }
        else if (global.stableColdRoomCount >= 4) { minDelta += 1.5; log.info("🔼 Стабильно холодно 4 цикла. Δ +1.5°C"); }
        else if (global.stableColdRoomCount >= 3) { minDelta += 1;   log.info("🔼 Стабильно холодно 3 цикла. Δ +1°C"); }

        if      (global.stableHotRoomCount >= 5) { minDelta -= 2;   log.info("🔽 Стабильно жарко 5 циклов. Δ −2°C"); }
        else if (global.stableHotRoomCount >= 4) { minDelta -= 1.5; log.info("🔽 Стабильно жарко 4 цикла. Δ −1.5°C"); }
        else if (global.stableHotRoomCount >= 3) { minDelta -= 1;   log.info("🔽 Стабильно жарко 3 цикла. Δ −1°C"); }

        global.lastColdestRoom = coldestRoom;

        // ── Расчёт новой температуры теплоносителя ────────────────────────────
        var correctionFactor = Math.abs(minDelta) > 2 ? 3 : Math.abs(minDelta) > 1 ? 2.5 : 2;
        var newWaterTemp = Math.round(baseWaterTemp + minDelta * correctionFactor);

        if (minDelta < 0 && newWaterTemp > currentWaterTemp) {
            newWaterTemp = currentWaterTemp;
            log.info("🔽 Перегрев: теплоноситель не повышается.");
        }
        if (minDelta >= -0.2 && minDelta <= 0.2) {
            newWaterTemp = Math.round(baseWaterTemp);
            log.info("🔄 Δ ≈ 0: сброс на базовое значение.");
        }
        newWaterTemp = Math.round(newWaterTemp);

        if (newWaterTemp > currentWaterTemp && global.stableHotRoomCount >= 3) {
            log.warn("🔽 Стабильно жарко, но теплоноситель растёт — принудительно понижаем.");
            newWaterTemp = Math.round(currentWaterTemp) - 1;
        }
        if (newWaterTemp < currentWaterTemp && global.stableColdRoomCount >= 3) {
            log.warn("🔼 Стабильно холодно, но теплоноситель падает — принудительно повышаем.");
            newWaterTemp = Math.round(currentWaterTemp) + 1;
        }

        // Пороги из ctx
        if (newWaterTemp < waterMin) newWaterTemp = waterMin;
        if (newWaterTemp > waterMax) newWaterTemp = waterMax;

        log.info("DEBUG: currentWaterTemp=" + currentWaterTemp + ", newWaterTemp=" + newWaterTemp + ", minDelta=" + minDelta);
        log.info("Коррекция: " + coldestRoom + ", Δ=" + minDelta.toFixed(1) + ", " + currentWaterTemp.toFixed(1) + "°C → " + newWaterTemp.toFixed(1) + "°C");

        // ── Telegram отчёт ────────────────────────────────────────────────────
        if (doTelegram) {
            var boilerOn    = isBoilerOnCtx(boilerUUID);
            var boilerEmoji = boilerOn ? "✅" : "❌";

            var roomLog = "🌡 Температура на улице: " + outsideTemp.toFixed(1) + "°C\n";
            roomLog += "📉 Прогноз через 6 часов: " + forecastTemp.toFixed(1) + "°C\n";
            roomLog += "💨 Скорость ветра: " + windSpeed.toFixed(1) + " м/с\n";
            roomLog += "🔆 УФ: " + uvIndex.toFixed(1) + ", " + cloudEmoji + " Облачность: " + cloudiness.toFixed(0) + "%\n";
            roomLog += "🔥 Базовая температура теплоносителя: " + baseWaterTemp.toFixed(1) + "°C " + boilerEmoji + "\n\n";

            // Режим если есть ctx
            if (ctx) {
                var modeStr = ctx.isHome ? (ctx.isNight ? "🌙 Ночь" : "☀️ День") : "🏠 Не дома";
                roomLog += "Режим: " + modeStr + "\n\n";
            }

            for (var room in rooms) {
                var currentTemp    = rooms[room].sensor;
                var targetRoomTemp = rooms[room].target;
                var delta          = targetRoomTemp - currentTemp;
                var deltaColor     = delta > 0 ? "🔴" : "🔵";
                var status         = "";
                var airQualityInfo = "";
                var rCfg           = (roomsCfg && roomsCfg[room]) ? roomsCfg[room] : null;

                var windowOpen = rCfg ? isWindowOpenCtx(rCfg)    : isWindowOpen(room);
                var ventOn     = rCfg ? isVentilationOnCtx(rCfg) : isVentilationOn(room);
                var floorOn    = rCfg ? isFloorHeatingOnCtx(rCfg): isFloorHeatingOn(room);
                var radOn      = rCfg ? isRadiatorOnCtx(rCfg)    : isRadiatorOn(room);

                if (radOn)      status += " 💢";
                if (floorOn)    status += " ♨️";
                if (windowOpen) status += " 🪟";
                if (ventOn)     status += " 🌀";

                if (windowOpen || ventOn) {
                    var aqData = rCfg ? getAirQualityDataCtx(rCfg) : getAirQualityData(room);
                    if (aqData) airQualityInfo = " " + aqData.type + " " + aqData.value + " " + aqData.unit;
                }

                roomLog += "🏠 " + room + ": Сейчас " + currentTemp.toFixed(1) + "°C, Цель " + targetRoomTemp + "°C, " + deltaColor + " " + delta.toFixed(1) + "°C" + status + airQualityInfo + "\n";
            }

            roomLog += "\n🔥 Коррекция отопления:\nСамая холодная комната:\n";

            var ignoredList = Object.keys(rooms).filter(function(r) { return ignoreTemperature[r]; });
            ignoredList.forEach(function(r) {
                var d = rooms[r].target - rooms[r].sensor;
                roomLog += "🚫 " + d.toFixed(1) + "°C " + r + " игнорируется\n";
            });

            if (coldestRoom) {
                var d = rooms[coldestRoom].target - rooms[coldestRoom].sensor;
                roomLog += (d > 0 ? "🔴" : "🔵") + " " + d.toFixed(1) + "°C " + coldestRoom + "\n";
            }

            roomLog += "Текущий теплоноситель: " + currentWaterTemp.toFixed(1) + "°C\n";
            if (newWaterTemp !== currentWaterTemp) {
                roomLog += "Новый теплоноситель: " + newWaterTemp.toFixed(1) + "°C\n";
            } else {
                roomLog += "⚖️ Изменение не требуется.\n";
            }

            sendTG(roomLog);
        }

        // ── Запись новой температуры в котёл ─────────────────────────────────
        setBoilerTemp(boilerUUID, newWaterTemp);

    } catch (e) {
        log.error("⛔ Ошибка в adjust_heating: " + e.message);
        sendTG("⚠️ Критическая ошибка. Проверьте логи: " + e.message);
    }
};
